fn check_id(id: i32) -> Result<String, String> {
    if id > 0 { Ok(String::from("Valid")) } else { Err(String::from("Invalid")) }
}

fn main() {
    let res = check_id(-5).unwrap_or(String::from("Failed"));
    println!("{}", res);
}

